namespace sv_ef1819d05a284ad5b9a1109113caffcd.Services;

/// <summary>
/// Server-side implementation that simulates a slow backend with seeded data.
/// </summary>
public sealed class ServerShipmentService : IShipmentService
{
    private static readonly Dictionary<string, Shipment> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["PKG-001"] = new Shipment
        {
            TrackingNumber = "PKG-001",
            Status = "In Transit",
            Location = "Chicago, IL",
            EstimatedDelivery = new DateTimeOffset(2026, 5, 25, 17, 0, 0, TimeSpan.Zero),
            StatusUpdates =
            [
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 20, 8, 0, 0, TimeSpan.Zero), Description = "Package picked up", Location = "New York, NY" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 21, 14, 30, 0, TimeSpan.Zero), Description = "Arrived at sorting facility", Location = "Philadelphia, PA" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 22, 6, 15, 0, TimeSpan.Zero), Description = "In transit to destination", Location = "Chicago, IL" },
            ]
        },
        ["PKG-002"] = new Shipment
        {
            TrackingNumber = "PKG-002",
            Status = "Delivered",
            Location = "San Francisco, CA",
            EstimatedDelivery = new DateTimeOffset(2026, 5, 21, 12, 0, 0, TimeSpan.Zero),
            StatusUpdates =
            [
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 18, 9, 0, 0, TimeSpan.Zero), Description = "Package picked up", Location = "Seattle, WA" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 19, 16, 0, 0, TimeSpan.Zero), Description = "Arrived at distribution center", Location = "Portland, OR" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 20, 22, 0, 0, TimeSpan.Zero), Description = "Out for delivery", Location = "San Francisco, CA" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 21, 10, 45, 0, TimeSpan.Zero), Description = "Delivered", Location = "San Francisco, CA" },
            ]
        },
        ["PKG-003"] = new Shipment
        {
            TrackingNumber = "PKG-003",
            Status = "Processing",
            Location = "Dallas, TX",
            EstimatedDelivery = new DateTimeOffset(2026, 5, 28, 18, 0, 0, TimeSpan.Zero),
            StatusUpdates =
            [
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 22, 10, 0, 0, TimeSpan.Zero), Description = "Order received", Location = "Dallas, TX" },
            ]
        },
    };

    public async Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        await Task.Delay(1500, ct);

        SeedData.TryGetValue(trackingNumber, out var shipment);
        return shipment;
    }
